mapper.select:
SELECT IFNULL(reg.exchange_rate,1) AS exchange_rate,sdd.*
FROM o_shop_daily as sdd
left join o_shop as shop on shop.id = sdd.shop_id
left join o_shop_region as reg on reg.id = shop.region_id



        and sdd.date >= #{startDate}


        and sdd.date <= #{endDate}


        and sdd.platform_id = #{platformId}


        and sdd.region_id = #{regionId}


        and sdd.shop_id = #{shopId}


        and shop.manage_user_id = #{manageUserId}


        and shop.shop_group_id = #{shopGroupId}

SELECT sdd.region_id,IFNULL(reg.exchange_rate,1) AS exchange_rate,shop.manage_user_id,shop.shop_group_id,
sum(order_total) as order_total,sum(order_amount) as order_amount, sum(false_order_total) as false_order_total,sum(false_order_amount) as false_order_amount, sum(true_order_total) as true_order_total,sum(true_order_amount) as true_order_amount, sum(ad_fee) as ad_fee,sum(ad_click) as ad_click,sum(ad_click_fee) as ad_click_fee,sum(ad_roi) as ad_roi, sum(unit_price) as unit_price,sum(withdrawal_amount) as withdrawal_amount
FROM o_shop_daily as sdd left join o_shop as shop on shop.id = sdd.shop_id left join o_shop_region as reg on reg.id = shop.region_id
and sdd.date >= #{startDate}
and sdd.date <= #{endDate}
and sdd.region_id = #{regionId}
and shop.shop_group_id = #{shopGroupId}
GROUP BY sdd.region_id,reg.exchange_rate,shop.manage_user_id,shop.shop_group_id
